# Convert int64 to int for JSON serialization
def convert_int64_to_int(data):
  import numpy as np
  if isinstance(data, dict):
      return {key: convert_int64_to_int(value) for key, value in data.items()}
  elif isinstance(data, list):
      return [convert_int64_to_int(item) for item in data]
  elif isinstance(data, np.int64):
      return int(data)
  return data

def currentDatetime():
  import datetime
  import pytz

  # Specify your desired timezone (e.g., 'Asia/Kolkata' for Indian Standard Time)
  desired_timezone = 'Asia/Kolkata'

  # Get the current time in UTC
  utc_time = datetime.datetime.utcnow()

  # Convert to the desired timezone
  local_time = utc_time.replace(tzinfo=pytz.utc).astimezone(pytz.timezone(desired_timezone))

  # Format the local time
  formatted_time = local_time.strftime("%d-%m-%Y %H:%M:%S.%f")[:-3]

  # print(f"Current local time ({desired_timezone}): {formatted_time}")
  return formatted_time

