def get_n_days_earlier(date_str, n):
    from datetime import datetime, timedelta
    # Convert the string date to a datetime object
    date = datetime.strptime(date_str, "%Y-%m-%d")

    # Subtract n days from the date
    new_date = date - timedelta(days=n)

    # Convert the datetime object back to a string
    new_date_str = new_date.strftime("%Y-%m-%d")

    return new_date_str

def dict_to_dataframe(data):
    """
    Convert a nested dictionary to a pandas DataFrame.

    Parameters:
    data (dict): The dictionary to convert. It should have a structure like {'1d': {...}, '1wk': {...}}.

    Returns:
    pd.DataFrame: The converted DataFrame.
    """
    # Convert the dictionary to a DataFrame
    df = pd.DataFrame(data)

    # Reset the index to get the stock names as a column
    df = df.reset_index().rename(columns={'index': 'Stock'})

    return df



import smtplib
from email.mime.multipart import MIMEMultipart
from email.mime.text import MIMEText

def send_email(sender_email, password, subject, body, receiver_emails, smtp_server = "smtp.mail.yahoo.com"):
    """
    Send an email using Yahoo SMTP server.

    Parameters:
    sender_email (str): The sender's email address.
    password (str): The app-specific password for the sender's Yahoo account.
    subject (str): The subject of the email.
    body (str): The body content of the email.
    receiver_emails (list): A list of recipient email addresses.
    """
    # Email configuration

    port = 465  # For SSL

    # Create the email content
    message = MIMEMultipart()
    message["From"] = sender_email
    message["To"] = ", ".join(receiver_emails)
    message["Subject"] = subject

    message.attach(MIMEText(body, "plain"))

    # Connect to the server and send the email
    try:
        server = smtplib.SMTP_SSL(smtp_server, port)
        server.login(sender_email, password)
        text = message.as_string()
        server.sendmail(sender_email, receiver_emails, text)
        print("Email sent successfully!")
    except Exception as e:
        print(f"Error: {e}")
    finally:
        server.quit()

